import numpy as np
import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec
from matplotlib.widgets import Slider
from scipy.linalg import solve_continuous_are

# -- System matrices ----------------------------------------------------------
A = np.array([[0., 1.],
              [0., 0.]])
B = np.array([[0.],
              [1.]])
C = np.array([[1., 0.]])

# -- LQR design ---------------------------------------------------------------
Q_lqr = np.diag([100., 1.])
R_lqr = np.array([[1.]])

P_lqr = solve_continuous_are(A, B, Q_lqr, R_lqr)
K = np.linalg.inv(R_lqr) @ B.T @ P_lqr          # shape (1,2)

# -- Kalman filter design -----------------------------------------------------
Qn = np.diag([0.01, 0.1])                         # process noise covariance
Rn = np.array([[1.]])                              # measurement noise covariance

P_kal = solve_continuous_are(A.T, C.T, Qn, Rn)
L = P_kal @ C.T @ np.linalg.inv(Rn)              # shape (2,1)

# -- Simulation parameters ----------------------------------------------------
dt = 0.01
t  = np.arange(0., 10. + dt, dt)
N  = len(t)

np.random.seed(42)
proc_noise = np.random.randn(N, 2) * np.sqrt([0.01, 0.1])
meas_noise = np.random.randn(N, 1) * np.sqrt(1.0)

# -- Run simulation -----------------------------------------------------------
def run_sim(r_pos):
    """Simulate LQG for a given position setpoint r_pos (velocity setpoint = 0)."""
    r = np.array([r_pos, 0.])          # reference state

    x     = np.zeros(2)               # true state  [pos, vel]
    x_hat = np.zeros(2)               # estimated state

    xs     = np.zeros((N, 2))
    x_hats = np.zeros((N, 2))
    us     = np.zeros(N)

    for i in range(N):
        # setpoint steps in at t = 1 s
        ref = r if t[i] >= 1.0 else np.zeros(2)

        # control law on estimated state
        e     = x_hat - ref
        u     = float(-K @ e)
        us[i] = u

        # true state (Euler integration + process noise)
        x_dot = A @ x + B.flatten() * u + proc_noise[i]
        x     = x + x_dot * dt

        # noisy measurement
        y = C @ x + meas_noise[i]

        # Kalman observer update
        x_hat_dot = (A @ x_hat
                     + B.flatten() * u
                     + L.flatten() * (y.flatten() - (C @ x_hat).flatten()))
        x_hat = x_hat + x_hat_dot * dt

        xs[i]     = x
        x_hats[i] = x_hat

    return xs, x_hats, us

# -- Initial plot -------------------------------------------------------------
init_r = 5.0
xs, x_hats, us = run_sim(init_r)

print("Simulation complete. Setting up plot...")

fig = plt.figure(figsize=(12, 9))
plt.suptitle("LQG Control: Second-Order Position-Velocity System", y=0.98)

gs  = gridspec.GridSpec(4, 1, figure=fig, hspace=0.65)
ax1 = fig.add_subplot(gs[0])
ax2 = fig.add_subplot(gs[1])
ax3 = fig.add_subplot(gs[2])
ax4 = fig.add_subplot(gs[3])

# Setpoint line values
sp_line_vals = np.where(t >= 1.0, init_r, 0.0)

# -- Position subplot ---------------------------------------------------------
l_pos_true, = ax1.plot(t, xs[:, 0],     'b',   lw=1.5, label='True position')
