l_pos_sp,   = ax1.plot(t, sp_line_vals,  'k:',  lw=1.2, label='Setpoint')
ax1.set_ylabel('Position (m)')
ax1.set_title('Position')
ax1.legend(loc='upper left', fontsize=8)
ax1.grid(True, alpha=0.3)

# -- Velocity subplot ---------------------------------------------------------
