# -- Control input subplot ----------------------------------------------------
l_ctrl, = ax3.plot(t, us, 'g', lw=1.5, label='Control input u')
ax3.set_ylabel('Control (m/s^2)')
ax3.set_title('Control Input')
ax3.legend(loc='upper right', fontsize=8)
ax3.grid(True, alpha=0.3)

# -- Estimation error subplot -------------------------------------------------
l_err_pos, = ax4.plot(t, xs[:, 0] - x_hats[:, 0], 'm',   lw=1.2, label='Position error')
l_err_vel, = ax4.plot(t, xs[:, 1] - x_hats[:, 1], 'c--', lw=1.2, label='Velocity error')
ax4.axhline(0, color='k', lw=0.8)
ax4.set_xlabel('Time (s)')
ax4.set_ylabel('Error')
ax4.set_title('Kalman Estimation Error (True - Estimated)')
ax4.legend(loc='upper right', fontsize=8)
ax4.grid(True, alpha=0.3)

plt.tight_layout()

# -- Slider -------------------------------------------------------------------
fig.subplots_adjust(bottom=0.10)
ax_slider = fig.add_axes([0.15, 0.02, 0.70, 0.025])
slider    = Slider(ax_slider, 'Position Setpoint (m)', 0.0, 10.0,
                   valinit=init_r, valstep=0.1, color='steelblue')

def update(val):
    r_new  = slider.val
    xs_n, x_hats_n, us_n = run_sim(r_new)
    sp_new = np.where(t >= 1.0, r_new, 0.0)

    l_pos_true.set_ydata(xs_n[:, 0])
    l_pos_est.set_ydata(x_hats_n[:, 0])
    l_pos_sp.set_ydata(sp_new)

    l_vel_true.set_ydata(xs_n[:, 1])
    l_vel_est.set_ydata(x_hats_n[:, 1])

    l_ctrl.set_ydata(us_n)

    l_err_pos.set_ydata(xs_n[:, 0] - x_hats_n[:, 0])
    l_err_vel.set_ydata(xs_n[:, 1] - x_hats_n[:, 1])

    for ax in [ax1, ax2, ax3, ax4]:
        ax.relim()
        ax.autoscale_view()

    fig.canvas.draw_idle()
    print(f"Setpoint updated to {r_new:.1f} m")

slider.on_changed(update)

print("Plot ready. Use the slider to change the position setpoint.")
